INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('员工关系专员 - 达州（社招）', '其他', '达州', '民营企业', 4000, 5000, '熟练使用Office办公软件', '性格外向，具有一定的抗压能力，良好的自我学习激励能力；主动性强，执行力强，配合度高，沟通表达能力及服务意识较好；具有良好的沟通表达能力和团队精神，思维逻辑优秀', 1, '友好', '1. 团队建设与沟通：组织各类团建活动，增强团队凝聚力，建立有效沟通机制，保障信息畅通；2. 员工关怀与激励：关注员工工作生活状态，提供关怀支持，设计实施激励机制，激发员工工作积极性；3. 员工关注的事件管理：及时受理处理员工投诉，保障员工合理诉求，定期开展员工满意度调查，为管理优化提供依据；4. 劳动争议事件管理：通过有效沟通调解，预防和化解潜在的劳动争议，减少企业法律风险和经济损失；5. 完成临时行政工作安排', '员工关系支持、OD 组织发展支持、薪酬绩效支持', '大专及以上', '无强制专业限制', '经验不限，半年及以上工作经验优先', '社招（应届生可投）', '有员工关系、劳动争议处理相关经验；有人力资源管理师相关证书', '4k-5k/月', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '甲方（企业自有 HR 岗）'), ('员工关系专员 - 宁德（社招）', '其他', '宁德', '民营企业', 15000, 30000, '1. 熟悉企业劳动关系管理相关法律法规和行业趋势；2. 具备独立处理劳动纠纷的能力', '乐观、耐心，有同理心；具备良好的沟通协调能力与风险预判能力', 0, '一般', '1. 制定并完善公司员工关系管理制度和流程；2. 建立员工矛盾调解机构，做好预防工作；3. 组织开展员工敬业度和满意度调查，提升组织氛围；4. 建立健全内部员工沟通机制和渠道，及时响应并解决员工问题；5. 识别潜在用工风险，提出改善计划并实施；6. 处理劳动争议和突发事件，构建和谐劳动关系', '员工关系支持、OD 组织发展支持', '本科及以上', '法律专业优先', '3-5年相关工作经验', '社招（应届生可投）', '有大型企业员工关系管理经验；有法律职业资格证书', '15k-30k/月·16薪', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('员工关系专员（行政班） - 杭州（社招）', '互联网 / IT', '杭州', '民营企业', 8000, 13000, '1. 熟悉《劳动法》《劳动合同法》及国家和地方相关劳动法律法规；2. 能够熟练使用Excel、PowerPoint、Outlook等办公软件（透视表、Vlookup）', '学习能力强，工作积极主动，具有良好的沟通能力、亲和力、服务导向理念和良好的团队协作精神', 0, '一般', '1. 协调外包员工异动、解除、批量裁员等工作，及时跟进汇报动态，规避用工风险；2. 负责劳资风险制度的制定及风险控制机制的建立，处理员工劳资纠纷、仲裁、投诉及突发事件；3. 协助完善和优化员工关系方面的流程、管理制度，并贯彻执行；4. 负责外包员工工伤申报、等级鉴定等相关事宜', '员工关系支持', '本科及以上', '人力资源/劳动关系/法律专业相关', '1-3年，有1年以上员工关系处理经验，熟悉工厂蓝领/互联网电商/人力资源外包等行业优先', '社招（应届生可投）', '有劳动争议处理、工伤申报相关经验；有人力资源管理师相关证书', '8k-13k/月·14薪', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('ssc专员（员工关系） - 郑州（社招）', '文化传媒 / 广告', '郑州', '民营企业', 5000, 9000, '1. 熟悉人力资源全流程工作；2. 熟练使用Office办公软件', '具备一定的沟通能力和协调能力，执行力强，工作认真负责', 0, '一般', '1. 负责企业文化落地，关注部门成员状态；2. 为团队发展提供支持，包括招聘、培训、员工关系等人力资源工作；3. 办理员工入职、转正、调岗、离职手续管理以及劳动合同以及人事档案；4. 执行考勤、薪资核算、社保缴纳等工作；5. 完成领导安排的其他工作', '员工关系支持、招聘全流程执行、薪酬绩效支持、OD 组织发展支持', '大专及以上', '无强制专业限制', '1-3年，两年及以上人力资源工作经验，有短剧工作经验优先', '社招（应届生可投）', '有人力资源相关证书；有短视频/短剧行业人力资源工作经验', '5k-9k/月', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '甲方（企业自有 HR 岗）'), ('员工关系专员 - 杭州（社招）', '文化传媒 / 广告', '杭州', '民营企业', 5000, 8000, '1. 熟悉劳动合同法及基础用工流程；2. 熟练使用办公软件，做事有条理，执行力强', '具备良好沟通表达能力，亲和力强，擅长协调与问题处理；工作细致严谨、责任心强', 1, '友好', '1. 负责员工入离职办理、劳动合同签订、续签、解除及档案管理，确保用工规范合规；2. 组织新员工入职培训，讲解公司制度、企业文化、考勤福利、职场规范等内容；3. 维护员工关系，处理员工咨询、沟通反馈，协助化解简单劳动争议；4. 协助完成员工考勤、社保公积金增减员及相关人事手续办理；5. 完善人事流程表单、员工档案，做好数据整理与台账更新', '员工关系支持、OD 组织发展支持', '本科及以上', '人力资源、行政管理等相关专业优先', '1年以内，有人事/员工关系相关经验者优先', '社招（应届生可投）', '有人力资源管理师相关证书；有员工关系相关实习/工作经验', '5k-8k/月', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '甲方（企业自有 HR 岗）');